    "sps-commerce/sps-missing-pagination-query-parameters": {
      "description": "Collection GET endpoints SHOULD support pagination using query parameters. Offset or cursor based pagination is required.",
      "severity": "warn",
      "given": "$.paths[?(!@property.match(/.*\\/\\{[^}]+\\}\\/*.*/))].get",
      "then": [
        {
          "field": "parameters",
          "function": "schema",
          "functionOptions": {
            "schema": {
              "type": "array",
              "items": {
                "type": "object"
              },
              "contains": {
                "type": "object",
                "properties": {
                  "name": {
                    "const": "limit"
                  },
                  "in": {
                    "const": "query"
                  }
                }
              },
              "allOf": [
                {
                  "anyOf": [
                    {
                      "contains": {
                        "type": "object",
                        "properties": {
                          "name": {
                            "const": "offset"
                          },
                          "in": {
                            "const": "query"
                          }
                        }
                      }
                    },
                    {
                      "contains": {
                        "type": "object",
                        "properties": {
                          "name": {
                            "const": "cursor"
                          },
                          "in": {
                            "const": "query"
                          }
                        }
                      }
                    }
                  ]
                }
              ]
            }
          }
        }
      ],
      "tags": [
        "source:sps-commerce",
        "format:openapi",
        "category:pagination"
      ]
    },
